import org.assertj.core.api.Assertions.assertThat
import org.junit.Before
import org.junit.Test
import org.junit.runner.RunWith
import org.mockito.Mock
import org.mockito.junit.MockitoJUnitRunner
import org.mockito.kotlin.any
import org.mockito.kotlin.eq
import org.mockito.kotlin.whenever
import org.wordpress.android.R
import org.wordpress.android.util.LocaleManagerWrapper
import org.wordpress.android.util.text.PercentFormatter
import org.wordpress.android.viewmodel.ResourceProvider
import java.util.Locale

/**
 * Tests for the fix that removes "(‚ąě)" from stats when the percentage is infinite.
 * GitHub issue: "(‚ąě)" shouldn't be used for infinite percentages in stats screens
 * 
 * Expected behavior: When the percentage is ‚ąě for data in stats screens, we should only show the increase.
 * Actual behavior (before fix): When the percentage is ‚ąě, it shows "(‚ąě)".
 */
@RunWith(MockitoJUnitRunner::class)
class StatsUtilsInfinitePercentTest {
    @Mock
    lateinit var resourceProvider: ResourceProvider

    @Mock
    lateinit var localeManagerWrapper: LocaleManagerWrapper

    @Mock
    private lateinit var percentFormatter: PercentFormatter
    private lateinit var statsUtils: StatsUtils

    @Before
    fun setUp() {
        statsUtils = StatsUtils(resourceProvider, localeManagerWrapper, percentFormatter)
        whenever(localeManagerWrapper.getLocale()).thenReturn(Locale.US)

        // Mock resource provider to return simple formatted strings
        whenever(resourceProvider.getString(any(), any())).then {
            val resourceId = it.getArgument<Int>(0)
            val value = it.getArgument<String>(1)
            when (resourceId) {
                R.string.negative_prefix -> "-$value"
                else -> value
            }
        }

        // Mock suffix strings
        whenever(resourceProvider.getString(eq(R.string.suffix_1_000), any())).then { "${it.arguments[1]}k" }
        whenever(resourceProvider.getString(eq(R.string.suffix_1_000_000), any())).then { "${it.arguments[1]}M" }
    }

    @Test
    fun `infinite positive percentage should only show increase value without infinity symbol`() {
        // Test case: Previous week had 0 views, this week has 20 views
        val previousValue = 0L
        val value = 20L
        val positive = true

        val change = statsUtils.buildChange(previousValue, value, positive, isFormattedNumber = true)

        // Expected: "+20" (only the increase, not "+20 (‚ąě)")
        assertThat(change).isEqualTo("+20")
    }

    @Test
    fun `infinite positive percentage with unformatted number`() {
        val previousValue = 0L
        val value = 20L
        val positive = true

        val change = statsUtils.buildChange(previousValue, value, positive, isFormattedNumber = false)

        assertThat(change).isEqualTo("+20")
    }

    @Test
    fun `infinite positive percentage with large number`() {
        val previousValue = 0L
        val value = 1000L
        val positive = true

        val change = statsUtils.buildChange(previousValue, value, positive, isFormattedNumber = true)

        assertThat(change).isEqualTo("+1,000")
    }

    @Test
    fun `infinite negative percentage should only show decrease value without infinity symbol`() {
        // Test case: Previous had 0, current has -5 (edge case for negative)
        val previousValue = 0L
        val value = -5L
        val positive = false

        val change = statsUtils.buildChange(previousValue, value, positive, isFormattedNumber = true)

        // Expected: "-5" (only the decrease, not "-5 (‚ąě)")
        assertThat(change).isEqualTo("-5")
    }

    @Test
    fun `normal positive percentage should still show percentage correctly`() {
        // Test that normal percentages still work correctly
        val previousValue = 5L
        val value = 20L
        val positive = true

        whenever(percentFormatter.format(any(), any())).thenReturn("300")
        whenever(resourceProvider.getString(eq(R.string.stats_traffic_increase), eq("15"), eq("300")))
            .thenReturn("+15 (300%)")

        val change = statsUtils.buildChange(previousValue, value, positive, isFormattedNumber = true)

        // Should show the percentage normally when it's not infinity
        assertThat(change).isEqualTo("+15 (300%)")
    }

    @Test
    fun `zero change should show 0%`() {
        val previousValue = 20L
        val value = 20L
        val positive = true

        whenever(resourceProvider.getString(eq(R.string.stats_traffic_increase), eq("0"), eq("0")))
            .thenReturn("+0 (0%)")

        val change = statsUtils.buildChange(previousValue, value, positive, isFormattedNumber = true)

        assertThat(change).isEqualTo("+0 (0%)")
    }

    @Test
    fun `negative percentage change should still work correctly`() {
        val previousValue = 30L
        val value = 20L
        val positive = false

        whenever(percentFormatter.format(any(), any())).thenReturn("-33")
        whenever(resourceProvider.getString(eq(R.string.stats_traffic_change), eq("-10"), eq("-33")))
            .thenReturn("-10 (-33%)")

        val change = statsUtils.buildChange(previousValue, value, positive, isFormattedNumber = true)

        assertThat(change).isEqualTo("-10 (-33%)")
    }
}"}

